using Microsoft.EntityFrameworkCore;
class AppDbContext : DbContext
{
    public DbSet<Order> Orders => Set<Order>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF Core 9 breaking change: HasData no longer accepts non-deterministic values.
        // Use a fixed seed date instead of DateTime.UtcNow.
        modelBuilder.Entity<Order>().HasData(
            new Order { Id = 1, CreatedAt = new DateTime(2024, 1, 1, 0, 0, 0, DateTimeKind.Utc) });
    }
}
class Order { public int Id { get; set; } public DateTime CreatedAt { get; set; } }

// --- Cosmos DB context demonstrating EF Core 9 breaking changes ---

class CosmosDbContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        optionsBuilder.UseCosmos(
            "https://localhost:8081",
            "C2y6yDjf5/R+ob0N8A7Cgv30VRDJIWEHLM+4QDU5DE2nQ9nDuVTqobD4b8mGGyPMbIZnqyMsEcaGQy67XIw/Jw==",
            "EfAppDb");
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF Core 9 breaking change: Cosmos DB discriminator property is now "$type"
        // instead of "Discriminator". For existing documents using "Discriminator",
        // explicitly configure the old property name to maintain backward compatibility.
        modelBuilder.Entity<Product>(b =>
        {
            b.HasDiscriminator<string>("Discriminator");
            b.ToContainer("Products");
        });
    }

    // EF Core 9 breaking change: Synchronous I/O on Cosmos DB is no longer supported.
    // All queries must use async methods (ToListAsync, FirstOrDefaultAsync, etc.)
    public async Task<List<Product>> GetProductsAsync()
    {
        // WRONG in EF Core 9: Products.ToList() — throws InvalidOperationException
        // CORRECT: use async
        return await Products.ToListAsync();
    }
}

class Product
{
    public string Id { get; set; } = default!;
    public string Name { get; set; } = default!;
}

